```class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = 0, res = -1, prevTime = 0;
        for (auto& log : logs) {
            int time = log[1] - prevTime;
            if (time > maxTime) {
                maxTime = time;
                res = log[0];
            } else if (time == maxTime) {
                res = min(res, log[0]);
            }
            prevTime = log[1];
        }
        return res;
    }
};
